import React from 'react';

const Certificates = () => {
  const certificates = [
    { title: 'React Certification', issuer: 'Coursera', date: '2023' },
    { title: 'JavaScript Advanced', issuer: 'Udemy', date: '2022' },
  ];

  return (
    <section id="certificates" className="certificates">
      <h2>Certificates</h2>
      <div>
        {certificates.map((cert, index) => (
          <div key={index} className="certificate">
            <h3>{cert.title}</h3>
            <p>Issued by: {cert.issuer}</p>
            <p>Date: {cert.date}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Certificates;
